```python
@dataclass
class Bad:
    tags: list = []           # SAME list across every instance!

@dataclass
class Good:
    tags: list = field(default_factory=list)
```

```python
# BAD
by_lang = {}
for d in docs:
    if d.lang not in by_lang: by_lang[d.lang] = []
    by_lang[d.lang].append(d)

# GOOD
by_lang = defaultdict(list)
for d in docs: by_lang[d.lang].append(d)
```
